from flask import Flask, request, jsonify, g
import logging
import json
import time
from functools import wraps
import os

app = Flask(__name__)

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler('app.log'),
        logging.StreamHandler()
    ]
)

logger = logging.getLogger(__name__)

# Middleware to log requests
@app.before_request
def log_request_info():
    g.start_time = time.time()
    logger.info(f"Request: {request.method} {request.url}")
    logger.info(f"Headers: {dict(request.headers)}")
    
    if request.is_json:
        try:
            body_data = request.get_json()
            logger.info(f"Body: {json.dumps(body_data, indent=2)}")
        except Exception as e:
            logger.error(f"Error parsing JSON body: {str(e)}")
    elif request.form:
        logger.info(f"Form data: {dict(request.form)}")
    elif request.data:
        logger.info(f"Raw data: {request.data.decode('utf-8')}")

# Middleware to log responses
@app.after_request
def log_response_info(response):
    duration = time.time() - g.start_time
    logger.info(f"Response: {response.status_code} - Duration: {duration:.2f}s")
    logger.info(f"Response headers: {dict(response.headers)}")
    
    if response.is_json:
        try:
            response_data = response.get_json()
            logger.info(f"Response body: {json.dumps(response_data, indent=2)}")
        except Exception as e:
            logger.error(f"Error parsing JSON response: {str(e)}")
    
    return response

# Error handler
@app.errorhandler(Exception)
def handle_exception(e):
    logger.error(f"Unhandled exception: {str(e)}", exc_info=True)
    return jsonify({"error": "Internal server error"}), 500

# Authentication decorator
def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header:
            logger.warning("Authentication failed: No Authorization header")
            return jsonify({"error": "Authorization required"}), 401
        
        # Log authentication attempt for debugging
        logger.info(f"Authentication attempt: {auth_header}")
        
        # Simple token validation (replace with your actual logic)
        if auth_header.startswith('Bearer '):
            token = auth_header.split(' ')[1]
            logger.info(f"Token provided: {token}")
            
            # Simulate token validation
            if token == "valid_token":
                return f(*args, **kwargs)
            else:
                logger.warning("Authentication failed: Invalid token")
                return jsonify({"error": "Invalid token"}), 401
        else:
            logger.warning("Authentication failed: Invalid token format")
            return jsonify({"error": "Invalid token format"}), 401
    
    return decorated_function

